// בדיקת נתונים ועיבוד מקדים
const inputData = $input.all();

if (!inputData || inputData.length === 0) {
  throw new Error('לא התקבלו נתונים');
}

const webhookData = inputData[0].json;

// חילוץ מערך חברי המשפחה - טיפול במבנה body מקונן
let familyMembers = [];
if (Array.isArray(webhookData)) {
  familyMembers = webhookData;
} else if (webhookData.body && Array.isArray(webhookData.body)) {
  familyMembers = webhookData.body;
} else if (webhookData.body && webhookData.body.body && Array.isArray(webhookData.body.body)) {
  familyMembers = webhookData.body.body;
} else {
  console.log('מבנה נתוני Webhook:', JSON.stringify(webhookData, null, 2));
  throw new Error('מבנה נתונים לא תקין - מצופה מערך של חברי משפחה');
}

// אימות וניקוי נתונים
const validatedMembers = familyMembers.map((member, index) => {
  if (!member['מספר מזהה'] || !member['לקוח'] || !member['סלולרי']) {
    throw new Error(`חבר משפחה ${index + 1} חסרים שדות נדרשים`);
  }

  return {
    id: member['מספר מזהה'],
    name: member['לקוח'],
    age: parseInt(member['גיל']) || 0,
    income: parseInt(member['הכנסה']) || 0,
    phone: member['סלולרי'],
    city: member['עיר'] || '',
    maritalStatus: member['מצב משפחתי'] || '',
    children: parseInt(member['ילדים']) || 0,
    profession: member['מקצוע'] || '',
    mortgage: parseInt(member['משכנתא']) || 0,
    savings: parseInt(member['חסכונות']) || 0,
    isChild: member['מצב משפחתי'] === 'ילד' || parseInt(member['גיל']) < 18
  };
});

console.log(`✅ אומתו ${validatedMembers.length} חברי משפחה`);

return validatedMembers.map(member => ({ json: member }));

// לוגיקת קיבוץ משפחות
const inputData = $input.all();

if (!inputData || inputData.length === 0) {
  return [{ json: { families: [], individuals: [] } }];
}

// קיבוץ לפי מספר טלפון
const familyGroups = new Map();
const individuals = [];

inputData.forEach(item => {
  const member = item.json;
  const phone = member.phone;

  if (!phone) {
    individuals.push(member);
    return;
  }

  if (!familyGroups.has(phone)) {
    familyGroups.set(phone, []);
  }

  familyGroups.get(phone).push(member);
});

// עיבוד משפחות
const families = [];

familyGroups.forEach((members, phone) => {
  if (members.length === 0) return;

  const parents = members.filter(m => !m.isChild && m.age >= 18);
  const children = members.filter(m => m.isChild || m.age < 18);

  const totalIncome = parents.reduce((sum, p) => sum + p.income, 0);
  const totalSavings = members.reduce((sum, m) => sum + m.savings, 0);
  const totalMortgage = parents.reduce((sum, p) => sum + p.mortgage, 0);

  const primaryParent = parents.length > 0 ? 
    parents.reduce((prev, current) => (prev.income > current.income) ? prev : current) :
    members[0];

  const family = {
    familyId: `family_${phone.replace(/[^0-9]/g, '')}`,
    phone: phone,
    primaryParent: primaryParent,
    parents: parents,
    children: children,
    members: members,
    familySize: members.length,
    totalIncome: totalIncome,
    totalSavings: totalSavings,
    totalMortgage: totalMortgage,
    city: primaryParent.city,
    createdAt: new Date().toISOString()
  };

  families.push(family);
});

console.log(`✅ נוצרו ${families.length} פרופילי משפחה ו-${individuals.length} פרופילי יחיד`);

return [{ 
  json: { 
    families: families,
    individuals: individuals,
    totalFamilies: families.length,
    totalIndividuals: individuals.length,
    processedAt: new Date().toISOString()
  } 
}];

// יצירת תוכן אימייל
const inputData = $input.all()[0].json;
const { families, individuals, totalFamilies, totalIndividuals } = inputData;

const subject = `משפחות ביטוח - ${totalFamilies} משפחות ו-${totalIndividuals} יחידים`;

let htmlBody = `
<!DOCTYPE html>
<html dir="rtl" lang="he">
<head>
    <meta charset="UTF-8">
    <title>דוח משפחות ביטוח</title>
    <style>
        body { font-family: Arial, sans-serif; direction: rtl; margin: 20px; }
        .header { background: #1eaef7; color: white; padding: 20px; border-radius: 8px; margin-bottom: 20px; }
        .family-card { border: 1px solid #ddd; border-radius: 8px; padding: 15px; margin: 15px 0; background: #f9f9f9; }
        .family-header { background: #bf5700; color: white; padding: 10px; border-radius: 5px; margin-bottom: 10px; }
        .member { background: white; padding: 10px; margin: 5px 0; border-radius: 5px; border-right: 4px solid #fe3d51; }
        .summary { background: #5ffbfd; padding: 15px; border-radius: 8px; margin: 20px 0; }
    </style>
</head>
<body>
    <div class="header">
        <h1>🏠 דוח משפחות ביטוח - מערכת Rensto</h1>
        <p>נוצר ב: ${new Date().toLocaleDateString('he-IL')} בשעה ${new Date().toLocaleTimeString('he-IL')}</p>
    </div>
`;

htmlBody += `
    <div class="summary">
        <h2>📊 סיכום כללי</h2>
        <p><strong>סה"כ משפחות:</strong> ${totalFamilies}</p>
        <p><strong>סה"כ יחידים:</strong> ${totalIndividuals}</p>
        <p><strong>סה"כ אנשים:</strong> ${families.reduce((sum, f) => sum + f.familySize, 0) + totalIndividuals}</p>
    </div>
`;

families.forEach((family, index) => {
  htmlBody += `
    <div class="family-card">
        <div class="family-header">
            <h3>👨‍👩‍👧‍👦 משפחה ${index + 1}: ${family.primaryParent.name}</h3>
            <p>📞 ${family.phone} | 🏠 ${family.city} | 👥 ${family.familySize} בני משפחה</p>
        </div>

        <div class="family-members">
            <h4>👨‍👩‍👧‍👦 בני המשפחה:</h4>
`;

  family.members.forEach(member => {
    const role = member.isChild ? '👶 ילד' : '👤 מבוגר';
    htmlBody += `
            <div class="member">
                <strong>${member.name}</strong> (${member.age} שנים) - ${role}<br>
                💼 ${member.profession} | 💰 הכנסה: ₪${member.income.toLocaleString()}
            </div>
`;
  });

  htmlBody += `
        </div>

        <div class="family-finances">
            <h4>💰 מצב כלכלי:</h4>
            <p><strong>הכנסה משפחתית:</strong> ₪${family.totalIncome.toLocaleString()}</p>
            <p><strong>חסכונות:</strong> ₪${family.totalSavings.toLocaleString()}</p>
            <p><strong>משכנתא:</strong> ₪${family.totalMortgage.toLocaleString()}</p>
        </div>
    </div>
`;
});

htmlBody += `
    <div class="footer" style="margin-top: 30px; padding: 20px; background: #f0f0f0; border-radius: 8px; text-align: center;">
        <p>🤖 דוח זה נוצר אוטומטית על ידי מערכת Rensto</p>
        <p>📧 לשאלות: support@rensto.com | 🌐 www.rensto.com</p>
    </div>
</body>
</html>
`;

return [{
  json: {
    subject: subject,
    htmlBody: htmlBody,
    textBody: `דוח משפחות ביטוח - ${totalFamilies} משפחות ו-${totalIndividuals} יחידים`,
    families: families,
    individuals: individuals,
    totalFamilies: totalFamilies,
    totalIndividuals: totalIndividuals
  }
}];

// יצירת תגובה סופית
const emailData = $input.all()[0].json;
const familyData = $('👨‍👩‍👧‍👦 קיבוץ משפחות').all()[0].json;

const response = {
  success: true,
  familyProfiles: familyData.families,
  individualProfiles: familyData.individuals,
  summary: {
    totalFamilies: familyData.totalFamilies,
    totalIndividuals: familyData.totalIndividuals,
    totalPeople: familyData.families.reduce((sum, f) => sum + f.familySize, 0) + familyData.totalIndividuals
  },
  message: `פרופילי משפחה עובדו בהצלחה - ${familyData.totalFamilies} משפחות ו-${familyData.totalIndividuals} יחידים עובדו. התראה נשלחה ל-office@shellycover.co.il`,
  generatedAt: new Date().toISOString(),
  emailSent: true,
  emailSubject: emailData.subject
};

console.log('✅ תגובה סופית נוצרה:', JSON.stringify(response, null, 2));

return [{ json: response }];
